import{_ as a,o as n,c as e,ae as p}from"./chunks/framework.BIONGpTb.js";const t="/docs/assets/%E8%B7%A8%E5%9F%9F%E9%94%99%E8%AF%AF.9QKpjgg6.png",l="/docs/assets/%E8%AF%B7%E6%B1%82%E6%96%B9%E6%B3%95%E5%AF%BC%E8%87%B4%E8%B7%A8%E5%9F%9F.CryOXL6C.png",i="/docs/assets/%E9%9D%9E%E7%AE%80%E5%8D%95%E6%96%B9%E6%B3%95%E7%9A%84%E9%A2%84%E6%A3%80.60ckyebg.png",o="/docs/assets/%E9%A2%84%E6%A3%80%E5%86%85%E5%AE%B9.HgpSft6p.png",c="/docs/assets/contenttye%E5%BC%95%E5%8F%91%E7%9A%84%E8%B7%A8%E5%9F%9F%E9%97%AE%E9%A2%98.DBOMuWot.png",r="/docs/assets/%E8%87%AA%E5%AE%9A%E4%B9%89%E5%93%8D%E5%BA%94%E5%A4%B4.ChYE7Dil.png",E=JSON.parse('{"title":"响应头和请求头","description":"","frontmatter":{},"headers":[],"relativePath":"nodejs/响应头和请求头.md","filePath":"nodejs/响应头和请求头.md"}'),d={name:"nodejs/响应头和请求头.md"};function h(g,s,u,b,m,v){return n(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="响应头和请求头" tabindex="-1">响应头和请求头 <a class="header-anchor" href="#响应头和请求头" aria-label="Permalink to &quot;响应头和请求头&quot;">​</a></h1><h2 id="响应头" tabindex="-1">响应头 <a class="header-anchor" href="#响应头" aria-label="Permalink to &quot;响应头&quot;">​</a></h2><p>响应头是用来干什么的？</p><ul><li>响应头是在发起http请求的时候，带上的具有特性的信息，以键值对的方式出现</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>accept-ranges:bytes</span></span>
<span class="line"><span>cache-control:public, max-age=0</span></span>
<span class="line"><span>connection:keep-alive</span></span>
<span class="line"><span>content-length:2831</span></span>
<span class="line"><span>content-type:text/html; charset=UTF-8</span></span></code></pre></div><h2 id="响应头和跨域" tabindex="-1">响应头和跨域 <a class="header-anchor" href="#响应头和跨域" aria-label="Permalink to &quot;响应头和跨域&quot;">​</a></h2><p>什么是跨域CORS？因为浏览器存在着同源策略，所以当发起请求的时候，浏览器会根据同源策略进行限制 <strong>同源策略：协议域名端口号必须相同才能通信</strong></p><ul><li>这里使用express起一个简单的服务：</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.get(&#39;/info&#39;, (req, res) =&gt; {</span></span>
<span class="line"><span>    res.json({</span></span>
<span class="line"><span>        code: 200</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>})</span></span></code></pre></div><ul><li>前端使用fetch发送请求</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch(&#39;http://localhost:3000/info&#39;).then(res=&gt;res.json()).then(res=&gt;{</span></span>
<span class="line"><span>            console.log(res);</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>        })</span></span></code></pre></div><p>诶，可以看到这里显示了跨域错误，因为我们的域名和端口号都不一样，由于这是前后端分离的项目，所以这里的端口号肯定是不能重复的。localhost和127.0.0.1虽然域名不同，但是转换一下会发现也是不行的 <img src="`+t+`" alt=""></p><h3 id="解决跨域问题" tabindex="-1">解决跨域问题 <a class="header-anchor" href="#解决跨域问题" aria-label="Permalink to &quot;解决跨域问题&quot;">​</a></h3><p>这里我们使用express的use去起一个中间件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.use((req,res,next)=&gt;{</span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Allow-Origin&#39;,&#39;*&#39;) </span></span>
<span class="line"><span>    next()</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>请求在进来之后，都要先进入这个中间件处理。在这里设置一个响应头<strong>Access-Control-Allow-Origin</strong>，值设置成 * 。*表示通配符，这样设置之后，所有请求都能获得回应。所以一般我们设置特定的地址，仅仅让这些地址能跨域</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.use((req,res,next)=&gt;{</span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Allow-Origin&#39;,&#39;http://127.0.0.1:5500&#39;) </span></span>
<span class="line"><span>    next()</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>这样就只有我们http://127.0.0.1:5500的请求能请求到数据了</p><h2 id="请求方法导致的跨域问题" tabindex="-1">请求方法导致的跨域问题 <a class="header-anchor" href="#请求方法导致的跨域问题" aria-label="Permalink to &quot;请求方法导致的跨域问题&quot;">​</a></h2><p>我们服务端默认只支持 GET POST HEAD OPTIONS 请求，例如我们遵循restFui 要支持PATCH 或者其他请求</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch(&#39;http://localhost:3000/info&#39;,{</span></span>
<span class="line"><span>            method:&#39;PATCH&#39;</span></span>
<span class="line"><span>        }).then(res=&gt;res.json()).then(res=&gt;{</span></span>
<span class="line"><span>            console.log(res);</span></span>
<span class="line"><span>            </span></span>
<span class="line"><span>        })</span></span></code></pre></div><p>服务端也起一个接口：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.patch(&#39;/info&#39;, (req, res) =&gt; {</span></span>
<span class="line"><span>    res.json({</span></span>
<span class="line"><span>        code: 200,</span></span>
<span class="line"><span>        type: &#39;patch&#39;</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>发生了错误： <img src="`+l+'" alt=""></p><p><strong>Method PATCH is not allowed by Access-Control-Allow-Methods in preflight response.</strong> 这说明patch不在方法里面 设置里面加上这个就行了</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>res.setHeader(&#39;Access-Control-Allow-Methods&#39;,&#39;GET,POST,PUT,DELETE,PATCH&#39;)</span></span></code></pre></div><h2 id="预检请求" tabindex="-1">预检请求 <a class="header-anchor" href="#预检请求" aria-label="Permalink to &quot;预检请求&quot;">​</a></h2><p>预检请求是用来对请求做预检的，比如检查你有没有跨域，有的话请求都不用执行，直接404 三种情况会有预检：</p><ol><li>POST PATCH DELETE这些非简单方法发起请求</li><li>自定义了请求头部，就是定义了不属于默认的请求头的时候</li><li>带凭证的请求：当请求需要在跨域环境下发送和接收凭证（例如包含 cookies、HTTP 认证等凭证信息）时，浏览器会发送预检请求。</li></ol><h3 id="非简单方法发起请求" tabindex="-1">非简单方法发起请求 <a class="header-anchor" href="#非简单方法发起请求" aria-label="Permalink to &quot;非简单方法发起请求&quot;">​</a></h3><p>刚刚发送的PATCH请求就能看到预检请求 <img src="'+i+'" alt="非简单方法的预检"><img src="'+o+`" alt="预检内容"></p><h3 id="自定义了请求头部的预检" tabindex="-1">自定义了请求头部的预检 <a class="header-anchor" href="#自定义了请求头部的预检" aria-label="Permalink to &quot;自定义了请求头部的预检&quot;">​</a></h3><p>在这里发送一个POST请求</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch(&#39;http://localhost:3000/info&#39;, {</span></span>
<span class="line"><span>            method: &#39;POST&#39;,</span></span>
<span class="line"><span>            headers: {</span></span>
<span class="line"><span>                &#39;Content-Type&#39;: &#39;application/json&#39;</span></span>
<span class="line"><span>            }, body: JSON.stringify({</span></span>
<span class="line"><span>                name: &#39;kfjr&#39;</span></span>
<span class="line"><span>            })</span></span>
<span class="line"><span>        }).then(res =&gt; res.json()).then(res =&gt; {</span></span>
<span class="line"><span>            console.log(res);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        })</span></span></code></pre></div><p>先还没看到预检，看到报错了 <img src="`+c+`" alt=""><strong>Request header field contenttype is not allowed by Access-Control-Allow-Headers in preflight response</strong></p><ul><li>这个请求头没有包含在Access-Control-Allow-Headers中，这里说明，不是所有的请求头都是符合预设的，请求头后面再说 将content-type加入</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.use((req,res,next)=&gt;{</span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Allow-Origin&#39;,&#39;http://127.0.0.1:5500&#39;) </span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Allow-Methods&#39;,&#39;GET,POST,PUT,DELETE,PATCH&#39;) </span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Allow-Headers&#39;,&#39;Content-Type&#39;) //这里加上Content-Type，允许客户端发送JSON数据</span></span>
<span class="line"><span>    next()</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>可以看到这里也起了预检请求</p><h2 id="请求头" tabindex="-1">请求头 <a class="header-anchor" href="#请求头" aria-label="Permalink to &quot;请求头&quot;">​</a></h2><p>默认情况下cors仅支持客户端向服务器发送如下九个请求头</p><ol><li>Accept：指定客户端能够处理的内容类型。</li><li>Accept-Language：指定客户端偏好的自然语言。</li><li>Content-Language：指定请求或响应实体的自然语言。</li><li>Content-Type：指定请求或响应实体的媒体类型。</li><li>DNT (Do Not Track)：指示客户端不希望被跟踪。</li><li>Origin：指示请求的源（协议、域名和端口）。</li><li>User-Agent：包含发起请求的用户代理的信息。</li><li>Referer：指示当前请求的源 URL。</li><li>Content-type: application/x-www-form-urlencoded | multipart/form-data | text/plain 那你看这里是没有 <code>application/json</code>的，所以刚才我们在客户端发送这个的时候，需要在服务端设置</li></ol><h2 id="自定义响应头" tabindex="-1">自定义响应头 <a class="header-anchor" href="#自定义响应头" aria-label="Permalink to &quot;自定义响应头&quot;">​</a></h2><p>后端起一个get接口：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.get(&#39;/info&#39;, (req, res) =&gt; {</span></span>
<span class="line"><span>    res.set(&#39;kfjr&#39;,&#39;ymk&#39;);</span></span>
<span class="line"><span>    res.json({</span></span>
<span class="line"><span>        code: 200</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>设置了一个响应头：<strong>&#39;kfjr&#39;：&#39;ymk&#39;</strong></p><p>客户端打印一下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fetch(&#39;http://localhost:3000/info&#39;).then(res =&gt; {</span></span>
<span class="line"><span>            const headers = res.headers;</span></span>
<span class="line"><span>            console.log(headers.get(&#39;kfjr&#39;));</span></span>
<span class="line"><span>            return res.json();</span></span>
<span class="line"><span>        }).then(res =&gt; {</span></span>
<span class="line"><span>            console.log(res);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        })</span></span></code></pre></div><p><img src="`+r+`" alt=""> 会发现，打印出来的是null，这是因为自定义响应头想要被获取到必须在服务端设置暴露</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app.get(&#39;/info&#39;, (req, res) =&gt; {</span></span>
<span class="line"><span>    res.set(&#39;kfjr&#39;,&#39;ymk&#39;);</span></span>
<span class="line"><span>    res.setHeader(&#39;Access-Control-Expose-Headers&#39;,&#39;kfjr&#39;) //抛出这个自定义的响应头</span></span>
<span class="line"><span>    res.json({</span></span>
<span class="line"><span>        code: 200</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>})</span></span></code></pre></div><p>这样就拿到了</p>`,50)])])}const A=a(d,[["render",h]]);export{E as __pageData,A as default};
